INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VHH_2025_consolidated', 'VHH', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2024_consolidated', 'VHH', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2023_consolidated', 'VHH', 2023, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2023_parent', 'VHH', 2023, 'parent', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2022_consolidated', 'VHH', 2022, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2019_consolidated', 'VHH', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 1, 'Kiểm toán viên nhấn mạnh vấn đề về các khoản trả trước và chi phí phải trả đã tồn tại từ năm 2005, chưa được nhà thầu phát hành hóa đơn. Công ty có lỗ kế toán lũy kế lớn (-45.560 triệu VND) và đã điều chỉnh giảm chi phí khấu hao năm 2019.'),
('VHH_2020_consolidated', 'VHH', 2020, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2018_consolidated', 'VHH', 2018, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHH_2019_parent', 'VHH', 2019, 'parent', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHG_2025_consolidated', 'VHG', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn Chuẩn Việt', 'qualified', 1, 'Khoản lỗ lũy kế là 1.394.188.681.131 đồng (chiếm 92,95% vốn điều lệ). Công ty có nợ quá hạn tiền thuế phải nộp ngân sách nhà nước 4.200.205.640 đồng.'),
('VHH_2021_consolidated', 'VHH', 2021, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán AAC', 'qualified', 0, NULL),
('VHG_2024_consolidated', 'VHG', 2024, 'consolidated', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'qualified', 1, 'Công ty có khoản lỗ lũy kế 1.389.511.274.423 đồng chiếm 92,63% vốn điều lệ và nợ quá hạn tiền thuế 8.611.346.786 đồng, dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VHG_2021_consolidated', 'VHG', 2021, 'consolidated', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'qualified', 1, 'Công ty ghi nhận khoản lỗ lũy kế 1.359.545.792.840 đồng chiếm 90,64% vốn điều lệ và nợ quá hạn tiền thuế 10.772.735.786 đồng'),
('VHG_2023_consolidated', 'VHG', 2023, 'consolidated', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'qualified', 1, 'Công ty có khoản lỗ lũy kế 1.387.184.310.164 đồng chiếm 92,5% vốn điều lệ. Ngoài ra, tại ngày 31/12/2023 Công ty có khoản nợ quá hạn tiền thuế phải nộp Ngân sách nhà nước với số tiền 8.611.346.786 đồng. Các điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VHG_2022_consolidated', 'VHG', 2022, 'consolidated', 'Công ty TNHH Kiểm toán AFC Việt Nam – Chi nhánh Hà Thành', 'qualified', 1, 'Công ty lỗ lũy kế 1,386 tỷ VND chiếm 92.43% vốn điều lệ và nợ thuế quá hạn 10.77 tỷ VND.'),
